member.example:
Bind the Transform euler angles using a serialized binder field — the target Transform is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TransformEulerAnglesBinder _rotation;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Vector3 _rotation;
    }


Bind the Transform euler angles by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Transform _target;
        
        private TransformEulerAnglesBinder Rotation =>
            new(_target);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Vector3 _rotation;
    }

Switch the Transform euler angles between two values using a serialized binder field — the target Transform is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TransformEulerAnglesSwitcherBinder _isFlipped;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isFlipped;
    }


Switch the Transform euler angles between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private Transform _target;
        
        [SerializeField]
        private Vector3 _flippedAngles;
        
        [SerializeField]
        private Vector3 _defaultAngles;
        
        private TransformEulerAnglesSwitcherBinder IsFlipped => new(
            _target, _flippedAngles, _defaultAngles);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isFlipped;
    }
